	int Query() {
		return Query(1, 1, n, 0);
	}

struct Info {
	Info() :cnt(0), mnpre(0) {};
	Info(int cnt) :cnt(cnt), mnpre(cnt) {};

	// cnt：当前值域区间的数出现次数的总数
	// mnpre：区间内的最小{ cnt 前缀和 - 这个前缀和对应的需求(即下一个值) }
	int cnt, mnpre; 
	void apply(const Info& v) {
		// 如何单点修改
		cnt += v.cnt;
		mnpre += v.cnt;
	}
};
Info operator+(const Info& a, const Info& b) {
	Info c;
	c.cnt = a.cnt + b.cnt;
	c.mnpre = min(a.mnpre, a.cnt + b.mnpre); // 最小前缀和
	return c;
}
void solve(int CASE)
{
	var a = vector<Info>(2e6 + 2);
	fa(i, 1, 2e6 + 1)a[i].cnt = 0, a[i].mnpre = -i; // 初始化，先减掉需求

	int ac, dr; cin >> ac >> dr;
	int n; cin >> n;
	var p = vector<pii>(n + 1);
	fa(i, 1, n)cin >> p[i].px;
	fa(i, 1, n)cin >> p[i].py;
	fa(i, 1, n) {
		int val = max(0, p[i].px - ac) + max(0, p[i].py - dr);
		// 线段树下标从 1 开始，所以这边 + 1 的偏移
		a[val + 1].cnt++;
		a[val + 1].mnpre++;
	}
	var seg = SegmentTree<Info>(a);

	int q; cin >> q;
	while (q--) {
		int k, na, nd; cin >> k >> na >> nd;
		int res = max(0, p[k].px - ac) + max(0, p[k].py - dr) + 1;
		int nres = max(0, na - ac) + max(0, nd - dr) + 1;
		p[k] = { na,nd };
		seg.modify(res, -1), seg.modify(nres, 1);
		cout << seg.Query() << endl;
	}
	return;
}
